module top_module(
    input [3:0] in,
    input clk,            // Added clk as an input
    output reg [3:0] out
);reg [3:0] incremented_value;
reg [3:0] stage2_out;

always @(*) begin
    incremented_value = in + 1;
end

always @(*) begin
    if (incremented_value == 4'b1111) begin
        stage2_out = 4'b0000;
    end else begin
        stage2_out = incremented_value;
    end
end

always @(posedge clk) begin
    out <= stage2_out;
end

endmodule
